// Filtra parcelas disponibles segun forma_pago + presupuesto + tamano opcional.
// Agrupa lotes con mismos valores (precio + tamano) para no saturar al agente.
// Orden: menor a mayor precio.

const sheetItem = $('Fetch Google Sheet CSV').first().json;
const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();
if (!csvText || csvText.length < 100) {
  return [{ json: {
    ok: false,
    error: 'csv_fetch_failed',
    grupos: [],
    tool_output_text: 'No pude consultar el inventario en este momento. Puedo pasar tu caso al equipo si quieres.',
  } }];
}

const input = $('Execute Workflow Trigger').first().json || {};
const formaPago = (input.forma_pago || '').toString().toLowerCase().trim();
const presupuestoClp = Number(input.presupuesto_clp) || 0;
const pieClp = Number(input.pie_clp) || 0;
const tamanoRaw = (input.tamano_preferido || '').toString().toLowerCase().trim();

// Interpretar tamano_preferido: acepta '5000', '10000', '5000m2', '1 ha', 'hectarea', 'media hectarea', etc.
function parseTamanoPreferido(raw) {
  if (!raw) return { min: null, max: null };
  const s = raw.replace(/[\.,]/g, '').toLowerCase();
  if (s.includes('hectarea') || s === 'ha' || s.includes('1ha') || s.includes('1 ha')) return { min: 10000, max: 10000 };
  if (s.includes('media hectarea') || s.includes('0.5 ha')) return { min: 5000, max: 5000 };
  if (s === 'grande') return { min: 8000, max: null };
  if (s === 'chica' || s === 'chico' || s === 'pequena' || s === 'pequeno') return { min: null, max: 6000 };
  if (s === 'mediana' || s === 'medio' || s === 'media') return { min: 5000, max: 8000 };
  const digits = s.replace(/[^0-9]/g, '');
  if (digits) {
    const n = parseInt(digits, 10);
    // Tolerancia +/- 10% para que '5000' calze con 4800-5500, etc.
    const margen = Math.max(500, Math.round(n * 0.1));
    return { min: n - margen, max: n + margen };
  }
  return { min: null, max: null };
}
const rangoTamano = parseTamanoPreferido(tamanoRaw);

function parseCsv(text) {
  const rows = [];
  let row = [], field = '', inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i+1] === '"') { field += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (c === ',' && !inQuotes) {
      row.push(field); field = '';
    } else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i+1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else {
      field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const parseMoney = (s) => {
  if (!s) return null;
  const t = s.toString();
  if (t.includes('#DIV') || t.includes('#REF') || t.includes('#VALUE')) return null;
  const cleaned = t.replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseTamano = (s) => {
  if (!s) return null;
  const t = s.toString();
  const cleaned = t.replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const normalizeEstado = (raw) => {
  const e = (raw || '').toString().trim().toLowerCase();
  if (e.startsWith('disponi')) return 'disponible';
  if (e.startsWith('reserv')) return 'reservado';
  if (e.startsWith('vendi')) return 'vendido';
  return e || 'desconocido';
};
const fmtClp = (n) => {
  if (n === null || n === undefined) return 's/valor';
  return '$' + n.toLocaleString('es-CL');
};
const fmtTamano = (m2) => {
  if (m2 === null || m2 === undefined) return 's/tamano';
  if (m2 >= 10000) {
    const ha = (m2 / 10000);
    const haStr = ha % 1 === 0 ? ha.toString() : ha.toFixed(2);
    return `${haStr} ha`;
  }
  return `${m2.toLocaleString('es-CL')} m²`;
};

const rows = parseCsv(csvText);
const disponibles = [];
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  if (normalizeEstado(r[2]) !== 'disponible') continue;
  const tamano = parseTamano(r[3]);
  const precioContado = parseMoney(r[6]);
  const pieMinimo = parseMoney(r[10]);
  disponibles.push({
    numero: lote.toUpperCase(),
    tamano_m2: tamano,
    precio_contado: precioContado,
    pie_minimo_50pct: pieMinimo,
  });
}

if (disponibles.length === 0) {
  return [{ json: {
    ok: true,
    grupos: [],
    tool_output_text: 'En este momento no hay parcelas disponibles. Le aviso al equipo para que te contacten cuando entre alguna.',
  } }];
}

// Filtro por tamano (si aplica)
function passTamano(p) {
  if (rangoTamano.min === null && rangoTamano.max === null) return true;
  if (p.tamano_m2 === null) return false;
  if (rangoTamano.min !== null && p.tamano_m2 < rangoTamano.min) return false;
  if (rangoTamano.max !== null && p.tamano_m2 > rangoTamano.max) return false;
  return true;
}

let candidatas = disponibles.filter(passTamano);
let sinMatch = false;

if (formaPago === 'contado' && presupuestoClp > 0) {
  candidatas = candidatas.filter(p => p.precio_contado !== null && p.precio_contado <= presupuestoClp);
} else if (formaPago === 'credito' && pieClp > 0) {
  candidatas = candidatas.filter(p => p.pie_minimo_50pct !== null && p.pie_minimo_50pct <= pieClp);
}

if (candidatas.length === 0) sinMatch = true;

const valorKey = formaPago === 'credito' ? 'pie_minimo_50pct' : 'precio_contado';

function agrupar(lista) {
  const map = new Map();
  for (const p of lista) {
    const valor = p[valorKey];
    const key = `${valor}|${p.tamano_m2}`;
    if (!map.has(key)) {
      map.set(key, {
        valor,
        tamano_m2: p.tamano_m2,
        precio_contado: p.precio_contado,
        pie_minimo_50pct: p.pie_minimo_50pct,
        lotes: [],
      });
    }
    map.get(key).lotes.push(p.numero);
  }
  return Array.from(map.values()).sort((a, b) => (a.valor || 0) - (b.valor || 0));
}

const grupos = agrupar(candidatas);

function formatGrupos(gs) {
  const labelValor = formaPago === 'credito' ? 'pie minimo 50%' : 'precio contado';
  return gs.map(g => {
    const lotesStr = g.lotes.length === 1
      ? `Lote ${g.lotes[0]}`
      : `Lotes ${g.lotes.join(', ')}`;
    return `${lotesStr} — ${fmtTamano(g.tamano_m2)} — ${fmtClp(g.valor)} (${labelValor})`;
  }).join('\n');
}

const tamanoMencion = tamanoRaw ? ` con ese tamano` : '';

let text;
if (sinMatch) {
  // Fallback: mostrar disponibles segun tamano (si habia filtro), o todas sin filtro
  const fallbackList = tamanoRaw ? disponibles.filter(passTamano) : disponibles;
  const gruposFallback = agrupar(fallbackList.length ? fallbackList : disponibles);
  const modo = formaPago === 'credito' ? 'ese pie' : 'ese presupuesto';
  text = `Con ${modo}${tamanoMencion} no encuentro parcelas que califiquen exactamente. Estas son las disponibles más cercanas:\n\n${formatGrupos(gruposFallback)}\n\nEl equipo puede revisar opciones adicionales si quieres.`;
} else {
  const modoLabel = formaPago === 'credito' ? 'ese pie' : 'ese presupuesto';
  text = `Con ${modoLabel}${tamanoMencion} califican estas parcelas disponibles (ordenadas de menor a mayor):\n\n${formatGrupos(grupos)}`;
}

return [{ json: {
  ok: true,
  forma_pago: formaPago,
  tamano_preferido: tamanoRaw,
  rango_tamano: rangoTamano,
  sin_match: sinMatch,
  total_disponibles: disponibles.length,
  total_califican: candidatas.length,
  grupos,
  tool_output_text: text,
} }];
